// Slack envía payload como form-urlencoded con campo `payload` = JSON string.
const raw = $json.body?.payload || $json.payload;
const payload = typeof raw === 'string' ? JSON.parse(raw) : raw;
const action = payload.actions?.[0];
const [role, decision] = action.action_id.split('_'); // legal_approve → ['legal','approve']
return [{ json: {
  run_id: action.value,
  role,
  decision,
  approver_slack: payload.user?.id,
  approver_name: payload.user?.username,
  response_url: payload.response_url,
  ts: new Date().toISOString()
}}];

const row = Array.isArray($json) ? $json[0] : $json;
const bothApproved = row.legal_status === 'approved' && row.admin_status === 'approved';
const anyRejected = row.legal_status === 'rejected' || row.admin_status === 'rejected';
let next_stage = row.stage;
if (anyRejected) next_stage = 'returned_to_submitter';
else if (bothApproved) next_stage = 'provider_action';
return [{ json: { ...row, bothApproved, anyRejected, next_stage } }];
